class Solution:
    def gameOfLife(self, board):
        # Independent: compute the whole next board into a fresh grid, then
        # copy it back so the rule is applied from a pristine snapshot.
        m = len(board)
        n = len(board[0]) if m else 0
        nxt = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                live = 0
                for di in (-1, 0, 1):
                    for dj in (-1, 0, 1):
                        if di == 0 and dj == 0:
                            continue
                        ni, nj = i + di, j + dj
                        if 0 <= ni < m and 0 <= nj < n and board[ni][nj] == 1:
                            live += 1
                if board[i][j] == 1:
                    nxt[i][j] = 1 if live in (2, 3) else 0
                else:
                    nxt[i][j] = 1 if live == 3 else 0
        for i in range(m):
            for j in range(n):
                board[i][j] = nxt[i][j]

